const hamburger=document.getElementById("hamburger"),navigacija=document.getElementById("navigacija");function meni(){navigacija.classList.toggle("active"),navigacija.classList.contains("active")?hamburger.innerHTML="✕":hamburger.innerHTML="☰"}hamburger.addEventListener("click",e=>{e.stopPropagation(),meni()}),document.querySelectorAll(".navigacija a").forEach(e=>{e.addEventListener("click",()=>{navigacija.classList.remove("active"),hamburger.innerHTML="☰"})}),document.addEventListener("click",e=>{navigacija.contains(e.target)||hamburger.contains(e.target)||(navigacija.classList.remove("active"),hamburger.innerHTML="☰")});let slajdovi=document.querySelectorAll(".slajd"),i=0;function showSlide(){slajdovi.forEach(e=>{e.classList.remove("active")}),slajdovi[i].classList.add("active"),++i>=slajdovi.length&&(i=0)}setInterval(showSlide,4e3);const a=document.querySelectorAll(".skriveno, .skriveno2");function prikazi(){let e=window.innerHeight;a.forEach(t=>{t.getBoundingClientRect().top<e-150?t.classList.add("pokazi"):t.classList.remove("pokazi")})}window.addEventListener("scroll",prikazi),window.addEventListener("load",prikazi),window.addEventListener("resize",prikazi);